mapper.select:
SELECT id, email, password_hash, display_name, bio, avatar_url, created_at, updated_at
FROM users
WHERE email = #{email}

SELECT id, email, password_hash, display_name, bio, avatar_url, created_at, updated_at
FROM users
WHERE id = #{id}

mapper.update:
UPDATE users
SET display_name = #{displayName}, bio = #{bio}, avatar_url = #{avatarUrl}, updated_at = now()
WHERE id = #{id}

mapper.select:
SELECT u.id AS id, u.id AS user_id, u.display_name AS display_name, u.avatar_url AS avatar_url,
    EXISTS (SELECT 1 FROM follows f WHERE f.follower_id = #{currentUserId} AND f.followee_id = u.id) AS is_following
FROM users u
WHERE u.id != #{currentUserId}
AND u.display_name ILIKE '%' || #{query} || '%'
AND u.id < #{cursor}
ORDER BY u.id DESC
LIMIT #{limit}
